import anthropic


def fibonacci_with_claude(n: int) -> int:
    """
    Compute the nth Fibonacci number using Claude's tool_use capability.

    Args:
        n: The position in the Fibonacci sequence (0-indexed)

    Returns:
        The nth Fibonacci number
    """
    client = anthropic.Anthropic()

    # Define the tools that Claude can use
    tools = [
        {
            "name": "compute_fibonacci",
            "description": "Compute the nth Fibonacci number recursively",
            "input_schema": {
                "type": "object",
                "properties": {
                    "n": {
                        "type": "integer",
                        "description": "The position in the Fibonacci sequence (0-indexed)"
                    }
                },
                "required": ["n"]
            }
        }
    ]

    def fib_helper(num: int) -> int:
        """Helper function to compute Fibonacci iteratively for efficiency"""
        if num <= 1:
            return num
        a, b = 0, 1
        for _ in range(2, num + 1):
            a, b = b, a + b
        return b

    # Create a message with Claude asking it to use the tool
    response = client.messages.create(
        model="claude-3-5-sonnet-20241022",
        max_tokens=1024,
        tools=tools,
        messages=[
            {
                "role": "user",
                "content": f"Please compute the {n}th Fibonacci number using the compute_fibonacci tool."
            }
        ]
    )

    # Check if Claude wants to use the tool
    for content_block in response.content:
        if content_block.type == "tool_use" and content_block.name == "compute_fibonacci":
            # Get the n value from the tool input
            fib_n = content_block.input.get("n", n)
            # Compute the Fibonacci number
            result = fib_helper(fib_n)

            # Send the result back to Claude
            response = client.messages.create(
                model="claude-3-5-sonnet-20241022",
                max_tokens=1024,
                tools=tools,
                messages=[
                    {
                        "role": "user",
                        "content": f"Please compute the {n}th Fibonacci number using the compute_fibonacci tool."
                    },
                    {
                        "role": "assistant",
                        "content": response.content
                    },
                    {
                        "role": "user",
                        "content": [
                            {
                                "type": "tool_result",
                                "tool_use_id": content_block.id,
                                "content": str(result)
                            }
                        ]
                    }
                ]
            )

            return result

    # Fallback: if Claude didn't use the tool, compute directly
    return fib_helper(n)


def fibonacci(n: int) -> int:
    """
    Compute the nth Fibonacci number using an iterative approach.

    Args:
        n: The position in the Fibonacci sequence (0-indexed)

    Returns:
        The nth Fibonacci number
    """
    if n < 0:
        raise ValueError("n must be non-negative")
    if n <= 1:
        return n

    a, b = 0, 1
    for _ in range(2, n + 1):
        a, b = b, a + b
    return b


if __name__ == "__main__":
    # Test the function with a few examples
    test_cases = [0, 1, 5, 10, 20]

    print("Testing fibonacci function:")
    for test_n in test_cases:
        result = fibonacci(test_n)
        print(f"fibonacci({test_n}) = {result}")

    print("\nTesting fibonacci_with_claude function:")
    for test_n in test_cases[:3]:  # Test with fewer cases to avoid too many API calls
        result = fibonacci_with_claude(test_n)
        print(f"fibonacci_with_claude({test_n}) = {result}")
